// Copyright 2019 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.package uniximport "unsafe"// FcntlInt performs a fcntl syscall on fd with the provided command and argument. FcntlInt(fd uintptr, cmd, arg int) (int, error) {turn fcntl(int(fd), cmd, arg)}// FcntlFlock performs a fcntl syscall for the F_GETLK, F_SETLK or F_SETLKW command. FcntlFlock(fd uintptr, cmd int, lk *Flock_t) error {_ rr := fcntl(int(fd), cmd, int(uintptr(unsafe.Pointer(lk))))reur err}// FcntlFstore performs a fcntl syscall for the F_PREALLOCATE command. FcntlFstore(fd uintptr, cmd int, fstore *Fstore_t) error {_, rr = fcntl(int(fd), cmd, int(uintptr(unsafe.Pointer(fstore))))retun er}